INSERT INTO t_p5815085_family_assistant_pro.feedback (type, user_name, user_email, title, description, rating, status, user_id, created_at) VALUES
('review', 'Елена', '', 'Наконец-то порядок в семейных делах!', 'Раньше постоянно забывали кто за что отвечает, дети путались в расписании. Теперь всё в одном месте — обязанности расписаны, список покупок общий, даже дни рождения не забываем. Муж сначала скептически относился, а теперь сам каждый день заходит.', 5, 'new', 'demo-user-1', '2026-02-12T14:32:00'),
('review', 'Дмитрий', '', 'Удобно для большой семьи', 'У нас трое детей и постоянный хаос. Приложение помогло разгрузить голову — задачи видно, кто что делает понятно. Единственное, хотелось бы больше напоминаний. А так — пользуемся всей семьёй уже второй месяц, все довольны.', 4, 'new', 'demo-user-2', '2026-02-28T09:15:00'),
('review', 'Ольга М.', '', 'Семейное древо — это что-то!', 'Скачала ради интереса, а потом залипла на семейном древе. Внесла всех родственников до прабабушек, добавила фотографии — теперь показываю детям, откуда наш род. Очень трогательно получилось. Спасибо разработчикам за такую возможность!', 5, 'new', 'demo-user-3', '2026-03-10T20:45:00'),
('review', 'Артём и Катя', '', 'Пользуемся вдвоём, очень помогает', 'Живём вдвоём, но домашних дел всё равно полно. Раньше вечно спорили кто должен был купить молоко. Теперь список покупок общий, обязанности распределены — меньше конфликтов, больше времени друг на друга. Рекомендуем!', 5, 'new', 'demo-user-4', '2026-03-22T17:20:00'),
('review', 'Наталья К.', '', 'Хорошее приложение, но есть куда расти', 'В целом нравится — идея отличная, интерфейс приятный. Пользуюсь календарём и списком покупок. Хотелось бы добавить возможность прикреплять фото к задачам и синхронизацию с Google-календарём. Ставлю 4, но потенциал на 5 точно есть!', 4, 'new', 'demo-user-5', '2026-04-02T11:05:00');